def repairCars(ranks, cars):
    n = len(ranks)

    # initialize dp with -1 (means not computed)
    dp = [[-1] * (cars + 1) for _ in range(n)]

    def solve(ind, cars):
        # base cases
        if cars == 0:
            return 0
        if ind == n:
            return float('inf')

        # if already computed
        if dp[ind][cars] != -1:
            return dp[ind][cars]

        mini = float('inf')

        # try assigning i cars to current mechanic
        for i in range(1, cars + 1):
            cost = i * i * ranks[ind]
            next_cost = solve(ind + 1, cars - i)
            mini = min(mini, cost + next_cost)

        dp[ind][cars] = mini
        return mini

    return solve(0, cars)

